import{_ as t,o as a,c as i,a2 as o}from"./chunks/framework.DGp-bpT-.js";const u=JSON.parse('{"title":"Bot Skills","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://srebot.site360.tech/docs/en/guide/skills.md"}],["link",{"rel":"alternate","hreflang":"ru","href":"https://srebot.site360.tech/docs/guide/skills.md"}],["link",{"rel":"alternate","hreflang":"en","href":"https://srebot.site360.tech/docs/en/guide/skills.md"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://srebot.site360.tech/docs/guide/skills.md"}]]},"headers":[],"relativePath":"en/guide/skills.md","filePath":"en/guide/skills.md","lastUpdated":null}'),s={name:"en/guide/skills.md"};function l(r,e,n,c,d,h){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="bot-skills" tabindex="-1">Bot Skills <a class="header-anchor" href="#bot-skills" aria-label="Permalink to &quot;Bot Skills&quot;">​</a></h1><p>Skills are customizable text instructions (in Markdown format) that allow you to adapt the behavior of the SREBot LLM agent to the specifics of your organization&#39;s infrastructure without modifying the bot&#39;s code.</p><h2 id="why-are-skills-needed" tabindex="-1">Why are Skills needed? <a class="header-anchor" href="#why-are-skills-needed" aria-label="Permalink to &quot;Why are Skills needed?&quot;">​</a></h2><p>By default, SREBot uses general log and metric analysis algorithms. However, in real-world projects, the infrastructure often has unique characteristics:</p><ul><li>Specific logging formats (e.g., the application name is in a nested field like <code>json.appname</code> or <code>json.app_name</code>, rather than <code>app_name</code>).</li><li>Non-standard metric locations or custom PromQL queries.</li><li>Custom links to internal logging systems (Kibana, Loki) or internal wiki documentation.</li></ul><p>Skills allow you to pass this knowledge to the model when investigating incidents.</p><hr><h2 id="creating-a-skill" tabindex="-1">Creating a Skill <a class="header-anchor" href="#creating-a-skill" aria-label="Permalink to &quot;Creating a Skill&quot;">​</a></h2><p>To create a skill, navigate to the <strong>Skills</strong> section in the dashboard&#39;s sidebar and click the <strong>Create Skill</strong> button.</p><p>The skill creation form consists of the following fields:</p><h3 id="_1-metadata" tabindex="-1">1. Metadata <a class="header-anchor" href="#_1-metadata" aria-label="Permalink to &quot;1. Metadata&quot;">​</a></h3><ul><li><strong>Name:</strong> A descriptive name for the skill (e.g., <code>Log Parsing Rules for worker-billing</code>).</li><li><strong>Description:</strong> A brief summary of the skill&#39;s purpose.</li></ul><h3 id="_2-scope" tabindex="-1">2. Scope <a class="header-anchor" href="#_2-scope" aria-label="Permalink to &quot;2. Scope&quot;">​</a></h3><p>Determines which agents these instructions will apply to:</p><ul><li><strong>Organization:</strong> Instructions will apply to all bots within your organization.</li><li><strong>Specific Bot:</strong> Instructions are bound only to the selected bots.</li></ul><h3 id="_3-trigger-rules" tabindex="-1">3. Trigger Rules <a class="header-anchor" href="#_3-trigger-rules" aria-label="Permalink to &quot;3. Trigger Rules&quot;">​</a></h3><p>Allows you to automatically activate the skill only for specific alerts. You can specify a set of rules in <code>Key: Regex</code> format:</p><ul><li>For example: <code>namespace: production</code>, <code>alertname: OOMKilled</code>.</li><li>If no trigger rules are specified, the skill acts as a <strong>catch-all</strong> and applies to all incidents in the selected scope.</li></ul><h3 id="_4-markdown-instructions" tabindex="-1">4. Markdown Instructions <a class="header-anchor" href="#_4-markdown-instructions" aria-label="Permalink to &quot;4. Markdown Instructions&quot;">​</a></h3><p>Free-form text in Markdown format describing the rules and context. This text is dynamically appended to the LLM model&#39;s system prompt.</p><hr><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Upon receiving a new alert, the SREBot backend automatically performs the following steps:</p><ol><li><strong>Metadata Extraction:</strong> All labels and annotations are extracted from the incoming alert.</li><li><strong>Trigger Matching:</strong> Trigger rules for all active skills of the organization are evaluated using regular expressions.</li><li><strong>Priority Sorting:</strong> All matching skills are sorted by scope: first <strong>Global</strong>, then <strong>Organization-wide</strong>, and finally <strong>Bot-specific</strong>. Bot-specific instructions have the highest priority since they are placed at the end of the system prompt.</li><li><strong>Prompt Injection:</strong> The compiled block of instructions is injected into the LLM system message before starting the analysis loop.</li></ol>',24)])])}const p=t(s,[["render",l]]);export{u as __pageData,p as default};
